As an AI text model, I cannot directly render or display a 3D image. However, I can provide you with the **complete code** to generate a 3D house using **Three.js** (a popular JavaScript library for 3D graphics).

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the rendered model.

### 3D House Generator (Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 10);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const hemiLight = new THREE.HemisphereLight(0xffffff, 0x444444);
        hemiLight.position.set(0, 20, 0);
        scene.add(hemiLight);

        const dirLight = new THREE.DirectionalLight(0xffffff);
        dirLight.position.set(-3, 10, 10);
        dirLight.castShadow = true;
        scene.add(dirLight);

        // 4. Materials
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x55aa55 });
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x888888 });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0xaa4444 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x88ccff });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeometry = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeometry, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeometry = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeometry, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof (Pyramid)
        const roofGeometry = new THREE.ConeGeometry(8, 4, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeometry = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeometry, doorMaterial);
        door.position.set(0, 1, 4.1); // Slightly in front of wall
        houseGroup.add(door);

        // Windows (Simple squares)
        const windowGeometry = new THREE.BoxGeometry(2, 1.5, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeometry, windowMaterial);
        win1.position.set(-2.5, 4, 4.1);
        const win2 = new THREE.Mesh(windowGeometry, windowMaterial);
        win2.position.set(2.5, 4, 4.1);

        // Side Windows
        const win3 = new THREE.Mesh(windowGeometry, windowMaterial);
        win3.position.set(4.1, 4, -2.5);
        const win4 = new THREE.Mesh(windowGeometry, windowMaterial);
        win4.position.set(4.1, 4, 2.5);

        houseGroup.add(win1, win2, win3, win4);

        scene.add(houseGroup);

        // 6. Ground Plane (Infinite grass look)
        const groundGeo = new THREE.PlaneGeometry(1000, 1000);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x55aa55 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  Create a new file on your computer named `house.html`.
3.  **Paste** the code into that file and save it.
4.  **Double-click** `house.html` to open it in Chrome, Firefox, Safari, or Edge.

### What this code does:
*   **Scene Setup:** Creates a 3D world with a sky-blue background and fog.
*   **Lighting:** Adds ambient light and a directional light (simulating the sun) that casts shadows.
*   **Geometry:** Constructs a house using basic shapes:
    *   A **Box** for the walls.
    *   A **Cone** rotated to look like a pyramid roof.
    *   Smaller **Boxes** for the door and windows.
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
